    /// <summary>
    /// Class entry point. The system will call this method when a designated menu 
    /// is selected or when execution starts and this class is set as the startup class.
    /// </summary>
    /// <param name = "_args">The specified arguments.</param>
    public static void main(Args _args)
    {
        CustTrans  custtrans;
        VendTrans   vendtrans;
        CustInvoiceTrans   CustInvoiceTrans;
        CustInvoiceJour    CustInvoiceJour;
        VendInvoiceTrans   VendInvoiceTrans;
        VendInvoiceJour    VendInvoiceJour;
        SalesTable          salestable;
        SalesLine          salesline;
        PurchTable       purchtable;
        PurchLine    purchline;
        LedgerJournalTrans   LedgerJournalTrans;
        LedgerJournalTable  LedgerJournalTable;
        GeneralJournalAccountEntry   GeneralJournalAccountEntry;
        GeneralJournalEntry     GeneralJournalEntry;
        BankAccountTrans      BankAccountTrans;
        SOURCEDOCUMENTLINE SOURCEDOCUMENTLINE;
        SOURCEDOCUMENTheader SOURCEDOCUMENTheader;
        AssetTrans   AssetTrans;
        Ledger  ledger;
        DimensionFocusBalance DimensionFocusBalance;
        str entitycode = "U007";
        InventTrans   InventTrans;
        INVENTDIM INVENTDIM;
        INVENTSUM  INVENTSUM;
        vendtransopen vendtransopen;
        custtransopen custtransopen;
        CustSettlement  CustSettlement;
        VendSettlement  VendSettlement;
        ;
        // AssetTrans
        ttsbegin;
        while select forupdate AssetTrans where AssetTrans.dataareaid == entitycode
        {
            AssetTrans.dodelete();
        }
        ttscommit;

        //Banktrans
        ttsbegin;
        while select forupdate BankAccountTrans where BankAccountTrans.dataareaid == entitycode
        {
            BankAccountTrans.dodelete();
        }
        ttscommit;
        // custttrans
        ttsbegin;
        while select forupdate custtrans where custtrans.dataareaid == entitycode
        {
            custtrans.dodelete();
        }
        ttscommit;
        // vendtrans
        ttsbegin;
        while select forupdate vendtrans where vendtrans.dataareaid == entitycode
        {
            vendtrans.dodelete();
        }
        ttscommit;
        // custtransopen
        ttsbegin;
        while select forupdate custtransopen where custtransopen.dataareaid == entitycode
        {
            custtransopen.dodelete();
        }
        ttscommit;
        // vendtransopen
        ttsbegin;
        while select forupdate vendtransopen where vendtransopen.dataareaid == entitycode
        {
            vendtransopen.dodelete();
        }
        ttscommit;
        //custsettelement
        ttsbegin;
        while select forupdate CustSettlement where CustSettlement.dataareaid == entitycode
        {
            CustSettlement.dodelete();
        }
        ttscommit;
        //vendsettelement
        ttsbegin;
        while select forupdate vendSettlement where vendSettlement.dataareaid == entitycode
        {
            vendSettlement.dodelete();
        }
        ttscommit;
        // inventtrans
        ttsbegin;
        while select forupdate InventTrans where InventTrans.dataareaid == entitycode
        {
            InventTrans.dodelete();
        }
        ttscommit;
        // inventdim
        ttsbegin;
        while select forupdate INVENTDIM where INVENTDIM.dataareaid == entitycode
        {
            INVENTDIM.dodelete();
        }
        ttscommit;

        // INVENTSUMINVENTSUMINVENTSUMINVENTSUMINVENTSUM
        ttsbegin;
        while select forupdate INVENTSUM where INVENTSUM.dataareaid == entitycode
        {
            INVENTSUM.dodelete();
        }
        ttscommit;

        //LedgerJournalTrans
        ttsbegin;
        while select forupdate LedgerJournalTrans where LedgerJournalTrans.DataAreaId == entitycode
        {
            LedgerJournalTrans.doDelete();
        }
        ttscommit;

        //LedgerJournalTable
        ttsbegin;
        while select forupdate LedgerJournalTable where LedgerJournalTable.DataAreaId == entitycode
        {
            LedgerJournalTable.doDelete();
        }
        ttscommit;

        //CustInvoiceTrans

        ttsbegin;
        while select forupdate CustInvoiceTrans where CustInvoiceTrans.DataAreaId == entitycode
        {
            CustInvoiceTrans.doDelete();
        }
        ttscommit;
        //CustInvoiceJour
        ttsbegin;
        while select forupdate CustInvoiceJour where CustInvoiceJour.DataAreaId == entitycode
        {
            CustInvoiceJour.doDelete();
        }
        ttscommit;
        //VendInvoiceTrans
        ttsbegin;
        while select forupdate VendInvoiceTrans where VendInvoiceTrans.DataAreaId == entitycode
        {
            VendInvoiceTrans.doDelete();
        }
        ttscommit;

        //VendInvoiceJour

        ttsbegin;
        while select forupdate VendInvoiceJour where VendInvoiceJour.DataAreaId == entitycode
        {
            select forupdate SOURCEDOCUMENTheader where SOURCEDOCUMENTheader.RecId == VendInvoiceJour.SourceDocumentHeader
&&   SOURCEDOCUMENTheader.SourceRelationType == VendInvoiceJour.TableId;
            if(SOURCEDOCUMENTheader)
            {
                SOURCEDOCUMENTheader.doDelete();

            }
            select forupdate SOURCEDOCUMENTline where SOURCEDOCUMENTline.RecId == VendInvoiceJour.SourceDocumentLine
&&   SOURCEDOCUMENTline.SourceRelationType == VendInvoiceJour.TableId;
            if(SOURCEDOCUMENTline)
            {
                SOURCEDOCUMENTline.doDelete();

            }

            VendInvoiceJour.doDelete();
        }
        ttscommit;
        //salesline
        ttsbegin;
        while select forupdate salesline where salesline.dataareaid == entitycode
        {
            salesline.dodelete();
        }
        ttscommit;

        //salestable
        ttsbegin;
        while select forupdate salestable where salestable.DataAreaId == entitycode
        {
            salestable.doDelete();
        }
        ttscommit;
        //salestable
        ttsbegin;
        while select forupdate purchline where purchline.DataAreaId == entitycode
        {
            purchline.doDelete();
        }
        ttscommit;

        //PurchTable
        ttsbegin;

        while select forupdate PurchTable where PurchTable.DataAreaId == entitycode
        {
            PurchTable.doDelete();
        }
        ttscommit;
        //GeneralJournalEntry and GeneralJournalAccountEntry
        ttsbegin;
        while select forupdate GeneralJournalEntry where GeneralJournalEntry.SUBLEDGERVOUCHERDATAAREAID == entitycode
        {
            while  select forupdate  GeneralJournalAccountEntry where GeneralJournalAccountEntry.GeneralJournalEntry == GeneralJournalEntry.recid
                if(GeneralJournalAccountEntry)
            {
                GeneralJournalAccountEntry.doDelete();
            }
            GeneralJournalEntry.doDelete();

        }
        ttscommit;
        //DimensionFocusBalance
        ttsbegin;

        select * from ledger where ledger.Description == "NUSRICO MADAGASCAR SARL";
        {
            while  select forupdate  DimensionFocusBalance where DimensionFocusBalance.Ledger == ledger.recid
            if(DimensionFocusBalance)
            {
                DimensionFocusBalance.doDelete();
            }

        }
        ttscommit;
        info(strFmt("%1","Scussfully Deleted transactions records from U007 entity"));
    }
